    66→            projection_matrix: Matrix::zeros((n_features, n_components)),
    67→            mean: None,
    68→            scale: None,
    69→            config,
    70→            inverse_cache: Arc::new(RwLock::new(HashMap::new())),
    71→            fitted: false,
    72→            name: "BaseProjector".to_string(),
    73→        }
    74→    }
    75→    
    76→    /// Set the projection matrix and mark as fitted
    77→    pub fn set_projection_matrix(&mut self, matrix: Matrix) -> Result<(), MultivariousError> {
    78→        if matrix.is_empty() {
    79→            return Err(MultivariousError::InvalidParameter {
    80→                name: "projection_matrix".to_string(),
    81→                value: "empty matrix".to_string(),
    82→                reason: "projection matrix must have at least one component".to_string(),
    83→            });
    84→        }
    85→        
    86→        self.projection_matrix = matrix;
    87→        self.fitted = true;
    88→        // Clear the cache when projection matrix changes
    89→        self.inverse_cache.write().unwrap().clear();
    90→        Ok(())
    91→    }
    92→    
    93→    /// Set preprocessing parameters
    94→    pub fn set_preprocessing(&mut self, mean: Option<Vector>, scale: Option<Vector>) -> Result<(), MultivariousError> {
    95→        // Validate dimensions if provided
    96→        let n_features = self.projection_matrix.nrows();
    97→        
    98→        if let Some(ref m) = mean {
    99→            if m.len() != n_features {
   100→                return Err(MultivariousError::DimensionMismatch {
   101→                    expected: n_features.to_string(),
   102→                    actual: m.len().to_string(),
   103→                });
   104→            }
   105→        }
   106→        
   107→        if let Some(ref s) = scale {
   108→            if s.len() != n_features {
   109→                return Err(MultivariousError::DimensionMismatch {
   110→                    expected: n_features.to_string(),
   111→                    actual: s.len().to_string(),
   112→                });
   113→            }
   114→            // Check for zero or near-zero scale values
   115→            if s.iter().any(|&val| val.abs() < 1e-10) {
   116→                return Err(MultivariousError::InvalidParameter {
   117→                    name: "scale".to_string(),
   118→                    value: "contains zero or near-zero values".to_string(),
   119→                    reason: "scale values must be non-zero for division".to_string(),
   120→                });
   121→            }
   122→        }
   123→        
   124→        self.mean = mean;
   125→        self.scale = scale;
   126→        Ok(())
   127→    }
   128→    
   129→    /// Get the projection matrix
   130→    pub fn projection_matrix(&self) -> &Matrix {
   131→        &self.projection_matrix
   132→    }
   133→    
   134→    /// Apply preprocessing to data
   135→    fn preprocess(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
   136→        let mut result = data.clone();
   137→        
   138→        // Center the data
   139→        if let Some(ref mean) = self.mean {
   140→            for mut row in result.rows_mut() {
   141→                row -= mean;
   142→            }
   143→        }
   144→        
   145→        // Scale the data
   146→        if let Some(ref scale) = self.scale {
   147→            for mut row in result.rows_mut() {
   148→                row /= scale;
   149→            }
   150→        }
   151→        
   152→        Ok(result)
   153→    }
   154→    
   155→    /// Apply inverse preprocessing to data
   156→    fn inverse_preprocess(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
   157→        let mut result = data.clone();
   158→        
   159→        // Unscale the data
   160→        if let Some(ref scale) = self.scale {
   161→            for mut row in result.rows_mut() {
   162→                row *= scale;
   163→            }
   164→        }
   165→        
   166→        // Uncenter the data
   167→        if let Some(ref mean) = self.mean {
   168→            for mut row in result.rows_mut() {
   169→                row += mean;
   170→            }
   171→        }
   172→        
   173→        Ok(result)
   174→    }
   175→    
   176→    /// Compute hash for component indices (for caching)
   177→    fn compute_indices_hash(indices: &[usize]) -> u64 {
   178→        use std::collections::hash_map::DefaultHasher;
   179→        use std::hash::{Hash, Hasher};
   180→        
   181→        let mut hasher = DefaultHasher::new();
   182→        indices.hash(&mut hasher);
   183→        hasher.finish()
   184→    }
   185→    
   186→    /// Compute the pseudo-inverse for a subset of components
   187→    fn compute_partial_inverse(&self, component_indices: &[usize]) -> Result<Matrix, MultivariousError> {
   188→        // Extract the subset of the projection matrix
   189→        let n_features = self.projection_matrix.nrows();
   190→        let n_selected = component_indices.len();
   191→        
   192→        if n_selected == 0 {
   193→            return Err(MultivariousError::InvalidParameter {
   194→                name: "component_indices".to_string(),
   195→                value: "empty".to_string(),
   196→                reason: "at least one component must be selected".to_string(),
   197→            });
   198→        }
   199→        
   200→        // Create submatrix with selected components
   201→        let mut submatrix = Matrix::zeros((n_features, n_selected));
   202→        for (out_idx, &comp_idx) in component_indices.iter().enumerate() {
   203→            if comp_idx >= self.projection_matrix.ncols() {
   204→                return Err(MultivariousError::InvalidParameter {
   205→                    name: "component_index".to_string(),
   206→                    value: comp_idx.to_string(),
   207→                    reason: format!("out of bounds (max: {})", self.projection_matrix.ncols() - 1),
   208→                });
   209→            }
   210→            submatrix.column_mut(out_idx).assign(&self.projection_matrix.column(comp_idx));
   211→        }
   212→        
   213→        // Compute pseudo-inverse using SVD or other method
   214→        // For now, we'll use the transpose for orthogonal projections
   215→        // In a full implementation, this would use proper pseudo-inverse computation
   216→        Ok(submatrix.t().to_owned())
   217→    }
   218→}
