   220→impl Project for BaseProjector {
   221→    fn project(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
   222→        check_is_fitted(self.fitted, "BaseProjector")?;
   223→        check_dimensions_match(
   224→            data.ncols(),
   225→            self.projection_matrix.nrows(),
   226→            "data features",
   227→            "projector features"
   228→        )?;
   229→        
   230→        // Apply preprocessing if configured
   231→        let processed_data = if self.config.center || self.config.scale {
   232→            self.preprocess(data)?
   233→        } else {
   234→            data.clone()
   235→        };
   236→        
   237→        // Project: X * W where W is the projection matrix
   238→        Ok(processed_data.dot(&self.projection_matrix))
   239→    }
   240→    
