   258→impl Reconstruct for BaseProjector {
   259→    fn reconstruct(&self, projected: &Matrix) -> Result<Matrix, MultivariousError> {
   260→        check_is_fitted(self.fitted, "BaseProjector")?;
   261→        check_dimensions_match(
   262→            projected.ncols(),
   263→            self.projection_matrix.ncols(),
   264→            "projected components",
   265→            "projector components"
   266→        )?;
   267→        
   268→        // Reconstruct: X_proj * W^T
   269→        let reconstructed = projected.dot(&self.projection_matrix.t());
   270→        
   271→        // Apply inverse preprocessing if configured
   272→        if self.config.center || self.config.scale {
   273→            self.inverse_preprocess(&reconstructed)
   274→        } else {
   275→            Ok(reconstructed)
   276→        }
   277→    }
   278→}
