   280→impl PartialProject for BaseProjector {
   281→    fn project_components(&self, data: &Matrix, component_indices: &[usize]) -> Result<Matrix, MultivariousError> {
   282→        check_is_fitted(self.fitted, "BaseProjector")?;
   283→        check_dimensions_match(
   284→            data.ncols(),
   285→            self.projection_matrix.nrows(),
   286→            "data features",
   287→            "projector features"
   288→        )?;
   289→        
   290→        if component_indices.is_empty() {
   291→            return Ok(Matrix::zeros((data.nrows(), 0)));
   292→        }
   293→        
   294→        // Validate component indices
   295→        for &idx in component_indices {
   296→            if idx >= self.projection_matrix.ncols() {
   297→                return Err(MultivariousError::InvalidParameter {
   298→                    name: "component_index".to_string(),
   299→                    value: idx.to_string(),
   300→                    reason: format!("out of bounds (max: {})", self.projection_matrix.ncols() - 1),
   301→                });
   302→            }
   303→        }
   304→        
   305→        // Apply preprocessing if configured
   306→        let processed_data = if self.config.center || self.config.scale {
   307→            self.preprocess(data)?
   308→        } else {
   309→            data.clone()
   310→        };
   311→        
   312→        // Create result matrix
   313→        let n_samples = data.nrows();
   314→        let n_selected = component_indices.len();
   315→        let mut result = Matrix::zeros((n_samples, n_selected));
   316→        
   317→        // Project onto selected components
   318→        for (out_idx, &comp_idx) in component_indices.iter().enumerate() {
   319→            let component = self.projection_matrix.column(comp_idx);
   320→            let projected_values = processed_data.dot(&component);
   321→            result.column_mut(out_idx).assign(&projected_values);
   322→        }
   323→        
   324→        Ok(result)
   325→    }
   326→    
   327→    fn component_importance(&self) -> Result<Vector, MultivariousError> {
   328→        check_is_fitted(self.fitted, "BaseProjector")?;
   329→        
   330→        // For base projector, assume all components have equal importance
   331→        // Derived classes can override this with actual importance scores
   332→        Ok(Vector::ones(self.n_components()))
   333→    }
   334→}
