        self
    }

    pub fn scale(mut self, scale: Vector) -> Self {
        self.scale = Some(scale);
        self
    }

    pub fn config(mut self, config: ProjectorConfig) -> Self {
        self.config = config;
        self
    }

    pub fn name(mut self, name: String) -> Self {
        self.name = name;
        self
    }

    pub fn build(self) -> Result<BaseProjector, MultivariousError> {
