            [5.0, 6.0, 7.0, 8.0],
        ];

        let projected = projector.project(&data).unwrap();
        assert_eq!(projected.shape(), &[2, 2]);
        assert_eq!(projected[[0, 0]], 1.0);
        assert_eq!(projected[[0, 1]], 2.0);
        assert_eq!(projected[[1, 0]], 5.0);
        assert_eq!(projected[[1, 1]], 6.0);
    }

