   102→            config,
   103→        }
   104→    }
   105→    
   106→    /// Fit the PCA model to data
   107→    pub fn fit(&mut self, data: &Matrix) -> Result<(), MultivariousError> {
   108→        let (n_samples, n_features) = data.dim();
   109→        
   110→        if n_samples < 2 {
   111→            return Err(MultivariousError::InvalidParameter {
   112→                name: "n_samples".to_string(),
   113→                value: n_samples.to_string(),
   114→                reason: "PCA requires at least 2 samples".to_string(),
   115→            });
   116→        }
   117→        
   118→        if n_features < 1 {
   119→            return Err(MultivariousError::InvalidParameter {
   120→                name: "n_features".to_string(),
   121→                value: n_features.to_string(),
   122→                reason: "PCA requires at least 1 feature".to_string(),
   123→            });
   124→        }
   125→        
   126→        self.n_samples = n_samples;
   127→        
   128→        // Set up preprocessing
   129→        let mut pipeline = PreprocessPipeline::new();
   130→        
   131→        if self.config.use_correlation {
   132→            // Standardize (mean=0, std=1)
   133→            pipeline = pipeline.add_step(Box::new(Standardize::new()));
   134→        } else {
   135→            // Just center (mean=0)
   136→            pipeline = pipeline.add_step(Box::new(Center::new()));
   137→        }
   138→        
   139→        // Fit and transform the data
   140→        let preprocessed = pipeline.fit_transform(data)?;
   141→        self.preprocessor = Some(pipeline);
   142→        
   143→        // Determine number of components
   144→        let max_components = n_features.min(n_samples - 1);
   145→        let n_components = if let Some(n) = self.config.projector_config.n_components {
   146→            n.min(max_components)
   147→        } else if let Some(min_var) = self.config.min_variance_retained {
   148→            // Will determine after SVD
   149→            max_components
   150→        } else {
   151→            max_components
   152→        };
   153→        
   154→        // Configure SVD
   155→        let mut svd_config = self.config.svd_config.clone();
   156→        svd_config.n_components = Some(n_components);
   157→        
   158→        // Select SVD method
   159→        let svd_method = if self.config.svd_method == SvdMethod::Auto {
   160→            // Auto-select based on matrix size
   161→            if n_samples * n_features < 1000 {
   162→                SvdMethod::Full
   163→            } else if n_components < max_components / 2 {
   164→                SvdMethod::Truncated(n_components)
   165→            } else {
   166→                SvdMethod::Full
   167→            }
   168→        } else {
   169→            self.config.svd_method
   170→        };
   171→        
   172→        // Create SVD solver
   173→        let solver = svd_factory(svd_method, svd_config)?;
   174→        
   175→        // Compute SVD
   176→        let svd_result = solver.compute(&preprocessed)?;
   177→        
   178→        // Store singular values and compute variance explained
   179→        self.singular_values = svd_result.singular_values.clone();
   180→        
   181→        // Standard deviations are singular values scaled by sqrt(n-1)
   182→        let scale_factor = (n_samples - 1) as f64;
   183→        self.standard_deviations = &self.singular_values / scale_factor.sqrt();
   184→        
   185→        // Compute explained variance ratio
   186→        let variances = self.standard_deviations.mapv(|x| x * x);
   187→        self.total_variance = variances.sum();
   188→        
   189→        if self.total_variance > 0.0 {
   190→            self.explained_variance_ratio = &variances / self.total_variance;
   191→        } else {
   192→            self.explained_variance_ratio = Vector::zeros(variances.len());
   193→        }
   194→        
   195→        // Compute cumulative variance ratio
   196→        self.cumulative_variance_ratio = Vector::zeros(self.explained_variance_ratio.len());
   197→        let mut cumsum = 0.0;
   198→        for (i, &ratio) in self.explained_variance_ratio.iter().enumerate() {
   199→            cumsum += ratio;
   200→            self.cumulative_variance_ratio[i] = cumsum;
   201→        }
   202→        
   203→        // Determine final number of components if using min_variance_retained
   204→        let final_n_components = if let Some(min_var) = self.config.min_variance_retained {
   205→            // Find the number of components that explain at least min_var of variance
   206→            let n = self.cumulative_variance_ratio
   207→                .iter()
   208→                .position(|&x| x >= min_var)
   209→                .map(|i| i + 1)
   210→                .unwrap_or(n_components);
   211→            n.min(n_components)
   212→        } else {
   213→            n_components
   214→        };
