   221→                "SVD did not return V^T matrix".to_string()
   222→            ));
   223→        };
   224→        
   225→        // Create projection matrix (transpose of components for our convention)
   226→        let projection_matrix = components.t().to_owned();
   227→        
   228→        // Update base projector
   229→        self.base_projector = BaseProjector::new(projection_matrix, self.config.projector_config.clone())?;
   230→        
   231→        // Truncate variance arrays if needed
   232→        if final_n_components < self.singular_values.len() {
   233→            self.singular_values = self.singular_values.slice(ndarray::s![..final_n_components]).to_owned();
   234→            self.standard_deviations = self.standard_deviations.slice(ndarray::s![..final_n_components]).to_owned();
   235→            self.explained_variance_ratio = self.explained_variance_ratio.slice(ndarray::s![..final_n_components]).to_owned();
   236→            self.cumulative_variance_ratio = self.cumulative_variance_ratio.slice(ndarray::s![..final_n_components]).to_owned();
   237→        }
   238→        
   239→        self.svd_method = svd_method;
   240→        
   241→        Ok(())
   242→    }
