mod tests {
    use super::*;
    use crate::test_utils::{generate_low_rank_matrix, generate_random_matrix};
    use approx::assert_relative_eq;

    #[test]
    fn test_permutation_test_basic() {
        // Generate data with clear structure
        let mut data = generate_low_rank_matrix(50, 10, 2);

        // Add noise to make it more realistic
        let noise = generate_random_matrix(50, 10) * 0.1;
        data = data + noise;

        let config = PermutationConfig {
            n_permutations: 100,
            random_state: Some(42),
            parallel: false,
            ..Default::default()
        };

        let result = pca_permutation_test(&data, 3, &config).unwrap();

        assert_eq!(result.n_components, 3);
        assert_eq!(result.p_values.len(), 3);
        assert_eq!(result.n_permutations, 100);

        // First two components should be significant (p < 0.05)
        assert!(result.p_values[0] < 0.05);
        assert!(result.p_values[1] < 0.05);
        // Third component should not be significant
        assert!(result.p_values[2] > 0.05);
    }

    #[test]
    fn test_p_value_adjustments() {
        let p_values = Array1::from_vec(vec![0.001, 0.01, 0.03, 0.04, 0.3]);

        // Bonferroni
        let bonf = bonferroni_correction(&p_values);
        assert_relative_eq!(bonf[0], 0.005, epsilon = 1e-10);
        assert_relative_eq!(bonf[1], 0.05, epsilon = 1e-10);
        assert_relative_eq!(bonf[2], 0.15, epsilon = 1e-10);
        assert_relative_eq!(bonf[3], 0.20, epsilon = 1e-10);
        assert_relative_eq!(bonf[4], 1.0, epsilon = 1e-10);

        // Holm-Bonferroni
        let holm = holm_bonferroni_correction(&p_values);
        assert!(holm[0] <= bonf[0]); // Should be less conservative

        // Benjamini-Hochberg
        let bh = benjamini_hochberg_correction(&p_values);
        assert!(bh[0] <= holm[0]); // Should be least conservative
    }

    #[test]
    fn test_sequential_stopping() {
        // Generate random data (no structure)
        let data = generate_random_matrix(30, 10);

        let config = PermutationConfig {
            sequential: true,
            min_permutations: 50,
            max_permutations: 500,
            alpha: 0.05,
            random_state: Some(42),
            ..Default::default()
        };

        let result = pca_permutation_test(&data, 2, &config).unwrap();

        // For random data, should stop early as no components are significant
        assert!(result.n_permutations >= config.min_permutations);
        assert!(result.n_permutations < config.max_permutations);

        // All p-values should be non-significant
        assert!(result.p_values.iter().all(|&p| p > config.alpha));
    }

