use crate::common_types::{Matrix, Vector};
use crate::errors::MultivariousError;
use crate::pca::{Pca, PcaBuilder};
use crate::utils::eye;
use ndarray::Array1;
use rand::prelude::*;
use rayon::prelude::*;
use serde::{Deserialize, Serialize};

/// Result of a permutation test
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PermutationTestResult {
    /// Number of components tested
    pub n_components: usize,

    /// P-values for each component
    pub p_values: Vector,

    /// Test statistics for the original data
    pub original_stats: Vector,

    /// Test statistics from permutations for each component
    pub permutation_stats: Vec<Vector>,

    /// Number of permutations performed
    pub n_permutations: usize,

    /// Sequential testing decisions (if sequential testing was used)
    pub sequential_decisions: Option<Vec<ComponentDecision>>,

    /// Adjusted p-values (if adjustment was applied)
    pub adjusted_p_values: Option<Vector>,
}

/// Decision for a single component in sequential testing
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ComponentDecision {
    /// Component index
    pub component: usize,

    /// P-value for this component
    pub p_value: f64,

    /// Whether the component was deemed significant
    pub significant: bool,

    /// Number of permutations used for this component
    pub n_permutations: usize,
}

/// Configuration for permutation testing
#[derive(Debug, Clone)]
pub struct PermutationConfig {
    /// Number of permutations to perform
    pub n_permutations: usize,

    /// Significance level (alpha)
    pub alpha: f64,

    /// Random seed for reproducibility
    pub random_state: Option<u64>,

    /// Whether to use parallel processing
    pub parallel: bool,

    /// Number of threads for parallel processing (None = use all available)
    pub n_threads: Option<usize>,

    /// Whether to use sequential testing
    pub sequential: bool,

    /// Minimum number of permutations for sequential testing
    pub min_permutations: usize,

    /// Maximum number of permutations for sequential testing
    pub max_permutations: usize,

    /// P-value adjustment method
    pub adjustment: PValueAdjustment,
}

/// P-value adjustment methods
#[derive(Debug, Clone, Copy, Serialize, Deserialize)]
pub enum PValueAdjustment {
    /// No adjustment
    None,
    /// Bonferroni correction
    Bonferroni,
    /// Holm-Bonferroni correction
    HolmBonferroni,
    /// Benjamini-Hochberg (FDR) correction
    BenjaminiHochberg,
}

impl Default for PermutationConfig {
    fn default() -> Self {
        Self {
            n_permutations: 1000,
            alpha: 0.05,
            random_state: None,
            parallel: true,
            n_threads: None,
            sequential: false,
            min_permutations: 100,
            max_permutations: 10000,
            adjustment: PValueAdjustment::None,
        }
    }
}

/// Perform permutation test for PCA
///
/// This implements the permutation methodology from Vitale et al. (2017)
/// with support for sequential testing and P3 projections.
pub fn pca_permutation_test(
    data: &Matrix,
    n_components: usize,
    config: &PermutationConfig,
) -> Result<PermutationTestResult, MultivariousError> {
    let (n_samples, n_features) = data.dim();

    if n_samples < 3 {
        return Err(MultivariousError::InvalidParameter {
            name: "n_samples".to_string(),
            value: n_samples.to_string(),
            reason: "Permutation test requires at least 3 samples".to_string(),
        });
    }

    if n_components > n_features.min(n_samples - 1) {
        return Err(MultivariousError::InvalidParameter {
            name: "n_components".to_string(),
            value: n_components.to_string(),
            reason: format!("Maximum components is {}", n_features.min(n_samples - 1)),
        });
    }

    // Fit PCA on original data
    let mut pca = PcaBuilder::new()
        .n_components(n_components)
        .random_state(config.random_state.unwrap_or(42))
        .build();

    pca.fit(data)?;
    let original_stats = compute_test_statistics(&pca)?;

    // Perform permutation testing
    let (permutation_stats, n_perms) = if config.sequential {
        sequential_permutation_test(data, n_components, &original_stats, config)?
    } else {
        fixed_permutation_test(data, n_components, config)?
    };

    // Compute p-values
    let p_values = compute_p_values(&original_stats, &permutation_stats);

    // Apply p-value adjustment if requested
    let adjusted_p_values = match config.adjustment {
        PValueAdjustment::None => None,
        PValueAdjustment::Bonferroni => Some(bonferroni_correction(&p_values)),
        PValueAdjustment::HolmBonferroni => Some(holm_bonferroni_correction(&p_values)),
        PValueAdjustment::BenjaminiHochberg => Some(benjamini_hochberg_correction(&p_values)),
    };

    Ok(PermutationTestResult {
        n_components,
        p_values,
        original_stats,
        permutation_stats,
        n_permutations: n_perms,
        sequential_decisions: None, // TODO: Implement sequential decisions tracking
        adjusted_p_values,
    })
}

/// Compute test statistics for PCA components
///
/// Uses explained variance ratio as the test statistic
fn compute_test_statistics(pca: &Pca) -> Result<Vector, MultivariousError> {
    Ok(pca.explained_variance_ratio().clone())
}

/// Perform fixed number of permutations
fn fixed_permutation_test(
    data: &Matrix,
    n_components: usize,
    config: &PermutationConfig,
) -> Result<(Vec<Vector>, usize), MultivariousError> {
    let n_perms = config.n_permutations;
    let seed = config.random_state.unwrap_or(42);

    if config.parallel {
        // Parallel execution
        let stats: Vec<Vector> = (0..n_perms)
            .into_par_iter()
            .map(|i| {
                let mut rng = StdRng::seed_from_u64(seed + i as u64);
                permute_and_compute(data, n_components, &mut rng)
            })
            .collect::<Result<Vec<_>, _>>()?;

        Ok((stats, n_perms))
    } else {
        // Sequential execution
        let mut rng = StdRng::seed_from_u64(seed);
        let mut stats = Vec::with_capacity(n_perms);

        for _ in 0..n_perms {
            stats.push(permute_and_compute(data, n_components, &mut rng)?);
        }

        Ok((stats, n_perms))
    }
}

/// Perform sequential permutation test with early stopping
fn sequential_permutation_test(
    data: &Matrix,
    n_components: usize,
    original_stats: &Vector,
    config: &PermutationConfig,
) -> Result<(Vec<Vector>, usize), MultivariousError> {
    let seed = config.random_state.unwrap_or(42);
    let mut rng = StdRng::seed_from_u64(seed);
    let mut stats = Vec::new();

    // Start with minimum permutations
    for i in 0..config.min_permutations {
        stats.push(permute_and_compute(data, n_components, &mut rng)?);
    }

    // Continue until stopping criterion is met or max permutations reached
    for i in config.min_permutations..config.max_permutations {
        stats.push(permute_and_compute(data, n_components, &mut rng)?);

        // Check stopping criterion every 100 permutations
        if i % 100 == 0 {
            let p_values = compute_p_values(original_stats, &stats);

            // Stop if all p-values are clearly above or below threshold
            let min_p = p_values.iter().fold(1.0f64, |a, &b| a.min(b));
            let max_p = p_values.iter().fold(0.0f64, |a, &b| a.max(b));

            // Conservative stopping: stop if all components are clearly non-significant
            if min_p > config.alpha * 2.0 {
                break;
            }

            // Or if we have high confidence in significance
            if max_p < config.alpha / 2.0 && i >= config.n_permutations / 2 {
                break;
            }
        }
    }

    Ok((stats, stats.len()))
}

/// Permute data and compute statistics
fn permute_and_compute(
    data: &Matrix,
    n_components: usize,
    rng: &mut StdRng,
) -> Result<Vector, MultivariousError> {
    // Create permutation indices
    let n_samples = data.nrows();
    let mut indices: Vec<usize> = (0..n_samples).collect();
    indices.shuffle(rng);

    // Permute rows of data
    let mut permuted = Matrix::zeros(data.dim());
    for (new_idx, &old_idx) in indices.iter().enumerate() {
        permuted.row_mut(new_idx).assign(&data.row(old_idx));
    }

    // Fit PCA on permuted data
    let mut pca = PcaBuilder::new()
        .n_components(n_components)
        .build();

    pca.fit(&permuted)?;
    compute_test_statistics(&pca)
}

/// Compute p-values from permutation statistics
fn compute_p_values(original: &Vector, permutation_stats: &[Vector]) -> Vector {
    let n_perms = permutation_stats.len();
    let n_components = original.len();
    let mut p_values = Vector::zeros(n_components);

    for comp in 0..n_components {
        let original_stat = original[comp];
        let count = permutation_stats.iter()
            .filter(|perm_stats| perm_stats[comp] >= original_stat)
            .count();

        p_values[comp] = (count + 1) as f64 / (n_perms + 1) as f64;
    }

    p_values
}

/// Apply Bonferroni correction
fn bonferroni_correction(p_values: &Vector) -> Vector {
    let n = p_values.len() as f64;
    p_values.mapv(|p| (p * n).min(1.0))
}

/// Apply Holm-Bonferroni correction
fn holm_bonferroni_correction(p_values: &Vector) -> Vector {
    let n = p_values.len();
    let mut indexed: Vec<(usize, f64)> = p_values.iter()
        .enumerate()
        .map(|(i, &p)| (i, p))
        .collect();

    // Sort by p-value
    indexed.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());

    let mut adjusted = Vector::zeros(n);
    let mut cummax = 0.0f64;

    for (rank, &(idx, p)) in indexed.iter().enumerate() {
        let adj_p = (p * (n - rank) as f64).min(1.0);
        cummax = cummax.max(adj_p);
        adjusted[idx] = cummax;
    }

    adjusted
}

/// Apply Benjamini-Hochberg correction
fn benjamini_hochberg_correction(p_values: &Vector) -> Vector {
    let n = p_values.len();
    let mut indexed: Vec<(usize, f64)> = p_values.iter()
        .enumerate()
        .map(|(i, &p)| (i, p))
        .collect();

    // Sort by p-value
    indexed.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap());

    let mut adjusted = Vector::zeros(n);
    let mut cummin = 1.0f64;

    // Process in reverse order
    for (rank, &(idx, p)) in indexed.iter().enumerate().rev() {
        let adj_p = (p * n as f64 / (rank + 1) as f64).min(1.0);
        cummin = cummin.min(adj_p);
        adjusted[idx] = cummin;
    }

    adjusted
}

/// P3 projection for sequential testing
///
/// This implements the projection method from the paper for
/// removing the effect of previously tested components
pub fn p3_projection(
    data: &Matrix,
    tested_components: &Matrix,
) -> Result<Matrix, MultivariousError> {
    // P3 = I - V * V^T where V contains tested components
    let v = tested_components;
    let vt = v.t();
    let vvt = v.dot(&vt);

    // Create identity matrix
    let n = data.nrows();
    let identity = eye(n);

    // Compute projection matrix
    let p3 = identity - vvt;

    // Apply projection
    Ok(p3.dot(data))
}

